import { SecureStore } from 'expo'

 function genRandomToken() {
   return "xxxx-yyyy-zzzz-cccc"
 }


 async function genLocalSessionToken(forApp: boolean) : string{
    if (forApp === false){
      return genRandomToken();  
    }

    const existingLocalToken = await SecureStore.getItemAsync("LocalSessionToken");
    if (!existingLocalToken || existingLocalToken == null ){
      return genRandomToken(); 
    }else{ 
      return existingLocalToken;
     }
}